	fmt.Fprintf(out, "reason: %s\n", candidate.Reason)
	fmt.Fprintf(out, "stage: %s\n", candidate.Child.Stage)
	return nil
}

func activeSessionPath(state ManagerState) string {
	if state.ActiveChild == nil {
		return ""
	}
	return state.ActiveChild.SessionPath
}

